solutions.javascript:
// Solution
function filterArray(arr, x) {
	const result = [];
	for (let i = 0; i < arr.length; i++) {
		if (arr[i] > x) {
			result.push(arr[i]); // Corrected logic
		}
	}
	return result;
}
